using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Http;
using System.IdentityModel.Tokens.Jwt;

public class JwtAuthenticationMiddleware : IMiddleware
{
    private readonly TokenValidationParameters _validationParameters;

    public JwtAuthenticationMiddleware(TokenValidationParameters validationParameters)
    {
        _validationParameters = validationParameters;
    }

    public Task InvokeAsync(HttpContext context, RequestDelegate next)
    {
        if (context.Request.Headers.ContainsKey("Authorization"))
        {
            var authHeader = context.Request.Headers["Authorization"].FirstOrDefault();
            if (authHeader != null && authHeader.StartsWith("Bearer "))
            {
                var token = authHeader.Substring(7);
                var principal = new JwtSecurityTokenHandler().ValidateToken(token, _validationParameters, out var validatedToken);
                context.User = principal;
            }
        }

        return next(context);
    }
}